"use client";

import React, { useRef, useEffect, useState, useLayoutEffect, useCallback } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus, vs } from 'react-syntax-highlighter/dist/esm/styles/prism';
import { User, AlertCircle, Check, Copy, X, Save, Edit2, RefreshCw, Trash2, Clock, Brain, ChevronDown, ChevronRight, ExternalLink } from 'lucide-react';
import { Message, Role, Language, TextWrappingMode, Theme, AvatarVisibility } from '../types';
import { t } from '../utils/i18n';
import { KirbyIcon } from './Kirby';
import { ChatMessage } from './ChatMessage';

interface ChatInterfaceProps {
  messages: Message[];
  isLoading: boolean;
  onEditMessage: (id: string, newText: string) => void;
  onDeleteMessage: (id: string) => void;
  onRegenerate: (id: string) => void;
  language: Language;
  fontSize: number;
  textWrapping: TextWrappingMode;
  bubbleTransparency: number;
  showModelName: boolean;
  showResponseTimer?: boolean;
  theme: Theme;
  kirbyThemeColor: boolean;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  smoothAnimation?: boolean;
  avatarVisibility: AvatarVisibility;
}

const LoadingTimer = () => {
  const [tenths, setTenths] = useState(0);

  useEffect(() => {
    const startTime = Date.now();
    const interval = setInterval(() => {
      const elapsed = Date.now() - startTime;
      setTenths(Math.floor(elapsed / 100));
    }, 100);
    return () => clearInterval(interval);
  }, []);

  return (
    <span className="text-xs font-mono text-primary-600 dark:text-primary-400 ml-2 select-none min-w-[3ch]">
      {(tenths / 10).toFixed(1)}s
    </span>
  );
};

const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
    messages, 
    isLoading, 
    onEditMessage, 
    onDeleteMessage, 
    onRegenerate, 
    language, 
    fontSize, 
    textWrapping, 
    bubbleTransparency,
    showModelName,
    showResponseTimer = false,
    theme,
    kirbyThemeColor,
    onShowToast,
    smoothAnimation = true,
    avatarVisibility
}) => {
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const deleteTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const [previewImageUrl, setPreviewImageUrl] = useState<string | null>(null);

  // Track if the user has manually scrolled up to pause auto-scrolling
  const isUserScrolledUp = useRef(false);
  const scrollRafId = useRef<number | null>(null);
  const lastIsLoading = useRef(isLoading);

  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl';

  // --- Scroll Logic ---

  // 1. Check if user is near bottom to enable/disable sticky mode
  const handleScroll = () => {
    if (!scrollContainerRef.current) return;
    const { scrollTop, scrollHeight, clientHeight } = scrollContainerRef.current;

    // Threshold to consider "at bottom". 
    // Small threshold (20px) ensures that if user scrolls up slightly, we respect it immediately (stop auto-scroll).
    const isAtBottom = scrollHeight - scrollTop - clientHeight < 20;

    // We strictly track this state to allow reading history while generating
    isUserScrolledUp.current = !isAtBottom;
  };

  // 2. Callback passed to ChatMessage to trigger scroll on text expansion
  // This ensures smooth scrolling even if the network request finished but animation is still playing
  const scrollToBottom = useCallback(() => {
     if (scrollContainerRef.current && !isUserScrolledUp.current) {
         // Force scroll to absolute bottom
         scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
     }
  }, []);

  // 3. Reset scroll lock when new messages are added (User sent one, or History loaded)
  useLayoutEffect(() => {
      isUserScrolledUp.current = false;
  }, [messages.length]);

  // 4. Initial Snap to Top on New Generation
  useLayoutEffect(() => {
    // Detect edge: isLoading goes false -> true (Start of generation)
    if (!lastIsLoading.current && isLoading) {
        // Reset user scroll lock
        isUserScrolledUp.current = false;

        // Find the AI message and snap it to top
        requestAnimationFrame(() => {
            if (scrollContainerRef.current) {
                const container = scrollContainerRef.current;
                const messageElements = container.querySelectorAll('[data-role="model"]');
                const lastModelMessage = messageElements[messageElements.length - 1];

                if (lastModelMessage) {
                    lastModelMessage.scrollIntoView({ block: 'start', behavior: 'smooth' });
                } else {
                    container.scrollTop = container.scrollHeight;
                }
            }
        });
    }
    lastIsLoading.current = isLoading;
  }, [isLoading]);


  // 5. The Sticky Loop (Bottom Tracking during loading)
  // This runs continuously while isLoading is true for network phase
  useEffect(() => {
    if (!isLoading) {
      if (scrollRafId.current) cancelAnimationFrame(scrollRafId.current);
      return;
    }

    const loop = () => {
      const container = scrollContainerRef.current;
      if (container && !isUserScrolledUp.current) {
        const { scrollHeight, scrollTop, clientHeight } = container;
        const distanceFromBottom = scrollHeight - (scrollTop + clientHeight);

        // Sticky logic: If content pushes down, follow it, but allow the "Snap to Top" gap
        // We only force scroll if the bottom is obscured by more than threshold
        if (distanceFromBottom > 20) {
            container.scrollTop = scrollHeight - clientHeight;
        }
      }
      scrollRafId.current = requestAnimationFrame(loop);
    };

    loop();

    return () => {
      if (scrollRafId.current) cancelAnimationFrame(scrollRafId.current);
    };
  }, [isLoading]);

  // 6. Fallback: Handle non-streaming loads
  useLayoutEffect(() => {
    if (!isLoading && scrollContainerRef.current && !isUserScrolledUp.current) {
       scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
    }
  }, [messages.length, isLoading]);

  useEffect(() => {
    return () => {
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
    };
  }, [messages]);

  const startEditing = (msg: Message) => { 
    setEditingId(msg.id); 
    setConfirmDeleteId(null);
  };

  // Calculate dynamic background color for loading bubble based on transparency
  // Note: structure and basic styles are now in CSS .loading-bubble
  const borderAlpha = 0.5 + (bubbleTransparency / 100) * 0.5;
  const dynamicStyle = {
      backgroundColor: `rgba(var(--color-theme-primary-rgb), ${(bubbleTransparency / 100) * 0.15})`,
      borderColor: isVSCodeTheme ? 'transparent' : `rgba(var(--color-theme-primary-rgb), ${borderAlpha})`
  };

  const showLoadingAvatar = avatarVisibility === 'always' || avatarVisibility === 'model-only';

  if (messages.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center px-4">
        <div className="w-48 h-48 mb-6 animate-fade-in-up">
            <KirbyIcon theme={theme} isThemed={kirbyThemeColor} />
        </div>
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">{t('app.title', language)}</h1>
        <p className="text-gray-600 dark:text-gray-400 max-w-md">{t('msg.welcome_desc', language)}</p>
      </div>
    );
  }

  return (
    <>
      <div 
          ref={scrollContainerRef}
          onScroll={handleScroll}
          // Removed scroll-smooth to prevent fighting with JS scroll
          className="flex-1 overflow-y-auto p-2 md:p-4 h-full relative"
      >
        <div className="flex flex-col space-y-4 pb-4 min-h-0">
          {messages.map((msg, index) => (
              <div key={msg.id} data-role={msg.role}>
                  <ChatMessage
                      msg={msg}
                      isEditing={editingId === msg.id}
                      isConfirmingDelete={confirmDeleteId === msg.id}
                      isLoading={isLoading}
                      bubbleTransparency={bubbleTransparency}
                      textWrapping={textWrapping}
                      fontSize={fontSize}
                      showModelName={showModelName}
                      showResponseTimer={showResponseTimer}
                      language={language}
                      theme={theme}
                      kirbyThemeColor={kirbyThemeColor}
                      onEditMessage={onEditMessage}
                      onDeleteMessage={onDeleteMessage}
                      onRegenerate={onRegenerate}
                      setEditingId={setEditingId}
                      setConfirmDeleteId={setConfirmDeleteId}
                      startEditing={startEditing}
                      deleteTimerRef={deleteTimerRef}
                      onShowToast={onShowToast}
                      smoothAnimation={smoothAnimation}
                      isLast={index === messages.length - 1}
                      onScrollToBottom={scrollToBottom}
                      avatarVisibility={avatarVisibility}
                      onViewImage={setPreviewImageUrl}
                  />
              </div>
          ))}

          {isLoading && (
              <div className={`flex justify-start w-full ${containerClass} mx-auto animate-fade-in-up px-2 md:px-0`} data-role="loading">
              <div className="flex gap-3">
                  {showLoadingAvatar && (
                      <div className="flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center overflow-hidden">
                          <div className="w-full h-full scale-150">
                              <KirbyIcon theme={theme} isThemed={kirbyThemeColor} />
                          </div>
                      </div>
                  )}
                  <div 
                      className="loading-bubble"
                      style={dynamicStyle}
                  >
                      <div className="typing-dot" style={{ animationDelay: '0ms' }}></div>
                      <div className="typing-dot" style={{ animationDelay: '150ms' }}></div>
                      <div className="typing-dot" style={{ animationDelay: '300ms' }}></div>
                      {showResponseTimer && <LoadingTimer />}
                  </div>
              </div>
              </div>
          )}

          {/* Dynamic Bottom Buffer */}
          <div 
              className="w-full transition-all duration-300 ease-out flex-shrink-0" 
              style={{ height: isLoading ? '160px' : '0px' }} 
              aria-hidden="true" 
          />
        </div>
      </div>

      {/* Lightbox / Full Screen Image Preview */}
      {previewImageUrl && (
        <div 
          className="fixed inset-0 z-[300] bg-black/90 backdrop-blur-sm flex items-center justify-center p-4 cursor-zoom-out animate-fade-in-up"
          onClick={() => setPreviewImageUrl(null)}
        >
          <img 
            src={previewImageUrl} 
            alt="Full Screen Preview" 
            className="max-w-full max-h-full object-contain rounded-lg shadow-2xl"
            onClick={() => setPreviewImageUrl(null)} // Ensure clicking image also closes
          />
          <button 
            onClick={() => setPreviewImageUrl(null)}
            className="absolute top-4 right-4 text-white/70 hover:text-white p-2 rounded-full hover:bg-white/10 transition-colors"
          >
             <X className="w-8 h-8" />
          </button>
        </div>
      )}
    </>
  );
};

export default ChatInterface;

"use client";

import React, { useRef, useState, useEffect, useLayoutEffect, useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus, vs } from 'react-syntax-highlighter/dist/esm/styles/prism';
import { User, AlertCircle, Check, Copy, X, Save, Edit2, RefreshCw, Trash2, Clock, Brain, ChevronDown, ChevronRight, ExternalLink } from 'lucide-react';
import { Message, Role, Language, TextWrappingMode, Theme, AvatarVisibility } from '../types';
import { t } from '../utils/i18n';
import { KirbyIcon } from './Kirby';

interface ChatMessageProps {
  msg: Message;
  isEditing: boolean;
  isConfirmingDelete: boolean;
  isLoading: boolean;
  bubbleTransparency: number;
  textWrapping: TextWrappingMode;
  fontSize: number;
  showModelName: boolean;
  showResponseTimer?: boolean;
  language: Language;
  theme: Theme;
  kirbyThemeColor: boolean;
  onEditMessage: (id: string, newText: string) => void;
  onDeleteMessage: (id: string) => void;
  onRegenerate: (id: string) => void;
  setEditingId: (id: string | null) => void;
  setConfirmDeleteId: (id: string | null) => void;
  startEditing: (msg: Message) => void;
  deleteTimerRef: React.MutableRefObject<ReturnType<typeof setTimeout> | null>;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  smoothAnimation?: boolean;
  isLast?: boolean;
  onScrollToBottom?: () => void;
  avatarVisibility: AvatarVisibility;
  onViewImage?: (url: string) => void;
}

const CodeBlock = ({ 
  value, 
  language, 
  lang, 
  theme,
  onShowToast 
}: { 
  value: string, 
  language: string, 
  lang: Language, 
  theme: Theme,
  onShowToast: (msg: string, type: 'success' | 'error' | 'info') => void 
}) => {
  const [copied, setCopied] = React.useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(value);
    setCopied(true);
    onShowToast(t('action.copied_code', lang), 'success');
    setTimeout(() => setCopied(false), 2000);
  };

  const isDarkTheme = ['dark', 'twilight', 'panda', 'vscode-dark'].includes(theme);
  const style = isDarkTheme ? vscDarkPlus : vs;

  return (
    <div className="relative my-4 rounded-lg overflow-hidden border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-[#1e1e1e] group shadow-sm">
      <div className="flex items-center justify-between px-3 py-2 bg-gray-100 dark:bg-[#252526] border-b border-gray-200 dark:border-gray-700">
        <span className="font-mono text-xs text-gray-500 dark:text-gray-400 font-medium">{language || 'text'}</span>
        <button 
          onClick={handleCopy} 
          className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-primary-600 dark:text-gray-400 dark:hover:text-primary-400 transition-colors bg-gray-200/50 dark:bg-gray-700/50 px-2 py-1 rounded"
          aria-label={copied ? t('action.copied_code', lang) : t('action.copy_code', lang)}
        >
          {copied ? <Check className="w-3.5 h-3.5 text-green-500" /> : <Copy className="w-3.5 h-3.5" />}
          <span>{copied ? t('action.copied', lang) : t('action.copy', lang)}</span>
        </button>
      </div>
      <div className="overflow-x-auto text-sm">
        <SyntaxHighlighter
          language={language || 'text'}
          style={style}
          customStyle={{
            margin: 0,
            padding: '1rem',
            background: 'transparent',
            fontSize: 'inherit',
          }}
          codeTagProps={{
            style: { fontFamily: 'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace' }
          }}
        >
          {value}
        </SyntaxHighlighter>
      </div>
    </div>
  );
};

const AutoResizeTextarea = ({ 
  value, 
  onChange, 
  onKeyDown, 
  fontSize, 
  autoFocus,
  lang 
}: { 
  value: string, 
  onChange: (e: React.ChangeEvent<HTMLTextAreaElement>) => void, 
  onKeyDown: (e: React.KeyboardEvent) => void, 
  fontSize: number,
  autoFocus?: boolean,
  lang: Language
}) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useLayoutEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  }, [value]);

  return (
    <textarea 
      ref={textareaRef}
      value={value} 
      onChange={onChange} 
      onKeyDown={onKeyDown} 
      className="w-full bg-transparent text-inherit rounded-none p-0 outline-none border-none focus:ring-0 resize-none overflow-hidden leading-relaxed font-inherit min-w-[200px] whitespace-normal break-words" 
      rows={1}
      style={{ fontSize: `${fontSize}px` }} 
      autoFocus={autoFocus} 
      aria-label={t('input.edit_message_content', lang)}
    />
  );
};

interface ThoughtBlockProps {
  text: string;
  lang: Language;
}

const ThoughtBlock: React.FC<ThoughtBlockProps> = ({ text, lang }) => {
  const [isOpen, setIsOpen] = useState(false); 

  return (
    <div className="my-3 border border-gray-200 dark:border-gray-700 rounded-lg bg-gray-50/50 dark:bg-gray-800/30 overflow-hidden">
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center gap-2 px-3 py-2 text-xs font-medium text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800/50 transition-colors"
      >
        <Brain className="w-3.5 h-3.5 text-gray-400" />
        <span>{t('label.thought_process', lang)}</span>
        <div className="ml-auto">
            {isOpen ? <ChevronDown className="w-3.5 h-3.5" /> : <ChevronRight className="w-3.5 h-3.5" />}
        </div>
      </button>
      {isOpen && (
         <div className="px-3 py-2 border-t border-gray-200 dark:border-gray-700 text-xs font-mono text-gray-600 dark:text-gray-400 whitespace-pre-wrap leading-relaxed">
             {text}
         </div>
      )}
    </div>
  );
};

export const ChatMessage: React.FC<ChatMessageProps> = React.memo(({
  msg,
  isEditing,
  isConfirmingDelete,
  isLoading,
  bubbleTransparency,
  textWrapping,
  fontSize,
  showModelName,
  showResponseTimer = false,
  language,
  theme,
  kirbyThemeColor,
  onEditMessage,
  onDeleteMessage,
  onRegenerate,
  setEditingId,
  setConfirmDeleteId,
  startEditing,
  deleteTimerRef,
  onShowToast,
  smoothAnimation = true,
  isLast = false,
  onScrollToBottom,
  avatarVisibility,
  onViewImage
}) => {
  const [editText, setEditText] = useState(msg.text);
  const [displayedText, setDisplayedText] = useState(msg.text);
  const targetTextRef = useRef(msg.text);
  const animationRef = useRef<number>(0);

  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl';

  // Detect if the message is a generated image (markdown image with data URI)
  const isGeneratedImage = useMemo(() => {
      const trimmed = msg.text.trim();
      return msg.role === Role.MODEL && trimmed.startsWith('![') && trimmed.includes('(data:image/');
  }, [msg.text, msg.role]);

  useEffect(() => {
    targetTextRef.current = msg.text;
    // Disable animation if user preference is off, role is not model, error, editing, OR if it is a generated image
    if (!smoothAnimation || msg.role !== Role.MODEL || isEditing || isGeneratedImage) {
        setDisplayedText(msg.text);
    }
  }, [msg.text, msg.role, isEditing, smoothAnimation, isGeneratedImage]);

  useEffect(() => {
    if (isEditing) setEditText(msg.text);
  }, [isEditing, msg.text]);

  useEffect(() => {
    if (!smoothAnimation || msg.role !== Role.MODEL || msg.isError || isEditing || isGeneratedImage) return;

    const animate = () => {
      setDisplayedText((current) => {
        const target = targetTextRef.current;
        if (current === target) return current;
        if (current.length > target.length) return target;

        const diff = target.length - current.length;
        let chunk = 2;
        if (diff > 50) chunk = 5;
        if (diff > 100) chunk = 15;
        if (diff > 500) chunk = 50; 

        const nextLen = Math.min(target.length, current.length + chunk);
        const nextText = target.substring(0, nextLen);
        return nextText;
      });
      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);
    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [msg.role, msg.isError, isEditing, smoothAnimation, isGeneratedImage]);

  useLayoutEffect(() => {
      if (isLast && onScrollToBottom && smoothAnimation && msg.role === Role.MODEL && !isEditing && !isGeneratedImage) {
          onScrollToBottom();
      }
  }, [displayedText, isLast, onScrollToBottom, smoothAnimation, msg.role, isEditing, isGeneratedImage]);

  const { thoughts, content } = useMemo(() => {
    if (msg.role !== Role.MODEL || isEditing) {
        return { thoughts: [], content: displayedText };
    }
    const thinkRegex = /<think>([\s\S]*?)(?:<\/think>|$)/g;
    const extractedThoughts: string[] = [];
    let match;
    while ((match = thinkRegex.exec(displayedText)) !== null) {
        extractedThoughts.push(match[1]);
    }
    const cleanContent = displayedText.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
    return { thoughts: extractedThoughts, content: cleanContent };
  }, [displayedText, msg.role, isEditing]);

  const cancelEditing = () => { 
    setEditingId(null); 
    setEditText(''); 
    setConfirmDeleteId(null);
  };

  const saveEdit = () => { 
    if (editText.trim() !== msg.text) onEditMessage(msg.id, editText); 
    setEditingId(null); 
    setConfirmDeleteId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => { 
    if (e.key === 'Enter' && !e.shiftKey) { 
      e.preventDefault(); 
      saveEdit(); 
    } 
    if (e.key === 'Escape') cancelEditing(); 
  };

  const handleDeleteClick = () => {
    setEditingId(null);
    if (isConfirmingDelete) {
      onDeleteMessage(msg.id);
      setConfirmDeleteId(null);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
    } else {
      setConfirmDeleteId(msg.id);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
      deleteTimerRef.current = setTimeout(() => {
        setConfirmDeleteId(null);
        deleteTimerRef.current = null;
      }, 3000);
    }
  };

  const handleRegenerateClick = () => {
    onRegenerate(msg.id);
    setConfirmDeleteId(null);
  }

  const handleImageClick = (src: string) => {
      if (onViewImage) {
          onViewImage(src);
      } else {
          // Fallback if view handler not provided
          window.open(src, '_blank');
      }
  };

  const getWrappingClass = () => {
    switch (textWrapping) {
      case 'forced': return 'whitespace-pre-wrap break-all';
      case 'auto': return 'whitespace-normal break-words';
      case 'default': default: return 'whitespace-pre-wrap break-words';
    }
  };

  const effectiveTransparency = isEditing ? 100 : bubbleTransparency;
  const borderAlpha = 0.5 + (effectiveTransparency / 100) * 0.5;
  const shadowAlpha = (100 - effectiveTransparency) / 100;

  const textShadowStyle = effectiveTransparency < 90 
    ? `0 1px 2px rgba(var(--color-theme-primary-rgb), ${shadowAlpha})` 
    : 'none';

  let backgroundColor;
  if (msg.role === Role.USER) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${effectiveTransparency / 100})`;
  } else if (msg.role === Role.MODEL && !msg.isError) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${(effectiveTransparency / 100) * 0.15})`;
  }

  const animationClass = smoothAnimation ? 'animate-pop-in' : '';
  const wrapperWidthClass = isEditing ? 'w-full max-w-full' : 'max-w-[95%] md:max-w-[85%]'; 
  const bubbleBorderColor = isVSCodeTheme ? 'transparent' : `rgba(var(--color-theme-primary-rgb), ${borderAlpha})`;

  const showAvatar = 
    avatarVisibility === 'always' || 
    (avatarVisibility === 'user-only' && msg.role === Role.USER) ||
    (avatarVisibility === 'model-only' && msg.role === Role.MODEL);

  return (
    <div className={`flex w-full ${containerClass} mx-auto ${msg.role === Role.USER ? 'justify-end' : 'justify-start'} animate-fade-in-up group`}>
        <div className={`flex gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} ${wrapperWidthClass}`}>

            {showAvatar && (
                <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center mt-0.5 overflow-hidden ${msg.role === Role.USER ? 'bg-primary-600' : 'bg-transparent'} ${msg.isError ? 'bg-red-500' : ''}`}>
                    {msg.role === Role.USER ? <User className="w-5 h-5 text-white" /> : <div className="w-full h-full scale-150"><KirbyIcon theme={theme} isThemed={kirbyThemeColor} /></div>}
                </div>
            )}

            <div className={`flex flex-col min-w-0 ${msg.role === Role.USER ? 'items-end' : 'items-start'} w-full`}>
            <div 
                className={`relative px-3 py-2.5 rounded-2xl shadow-sm backdrop-blur-sm transition-all duration-300 w-full max-w-full origin-bottom-left ${animationClass} ${
                    msg.role === Role.USER 
                    ? 'text-white rounded-tr-sm border origin-bottom-right' 
                    : msg.isError 
                        ? 'bg-red-100 dark:bg-red-900/30 border border-red-200 dark:border-red-800 text-red-800 dark:text-red-200 rounded-tl-sm' 
                        : 'border text-gray-800 dark:text-gray-100 rounded-tl-sm'
                }`}
                style={
                    !msg.isError ? { 
                        backgroundColor,
                        borderColor: bubbleBorderColor,
                        textShadow: textShadowStyle
                    } : {}
                }
            >
                {/* Image Grid for Message */}
                {msg.images && msg.images.length > 0 && !isEditing && (
                    <div className="flex flex-wrap gap-2 mb-2">
                        {msg.images.map((img, idx) => (
                            <div key={idx} className="relative group">
                                <img 
                                    src={img} 
                                    alt="Message Attachment" 
                                    className="max-h-64 max-w-full rounded-lg cursor-pointer hover:opacity-90 transition-opacity" 
                                    onClick={() => handleImageClick(img)}
                                />
                            </div>
                        ))}
                    </div>
                )}

                {isEditing ? (
                <div className="w-full min-w-[200px]">
                    <AutoResizeTextarea 
                        value={editText} 
                        onChange={(e) => setEditText(e.target.value)} 
                        onKeyDown={handleKeyDown} 
                        fontSize={fontSize}
                        autoFocus
                        lang={language}
                    />
                    <div className="flex justify-end gap-2 mt-2">
                        <button 
                        onClick={cancelEditing} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.cancel', language)}
                        aria-label={t('action.cancel_edit', language)}
                    >
                            <X className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                        <button 
                        onClick={saveEdit} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.confirm', language)}
                        aria-label={t('action.save_edit', language)}
                    >
                            <Save className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                    </div>
                </div>
                ) : (
                <>
                    {msg.isError ? (
                    <div className="flex items-center gap-2"><AlertCircle className="w-4 h-4" /><span>{msg.text}</span></div>
                    ) : (
                    <div className={`markdown-body ${getWrappingClass()}`} style={{ fontSize: `${fontSize}px` }}>
                        {thoughts.length > 0 && (
                            <div className="mb-3 flex flex-col gap-2">
                                {thoughts.map((thought, idx) => (
                                    <ThoughtBlock key={idx} text={thought} lang={language} />
                                ))}
                            </div>
                        )}
                        {/* Only render text content if it exists, otherwise images are handled above */}
                        {(content || (!msg.images || msg.images.length === 0)) && (
                             <ReactMarkdown 
                                remarkPlugins={[remarkGfm, remarkMath]} 
                                rehypePlugins={[rehypeKatex]} 
                                urlTransform={(value) => value}
                                components={{ 
                                    code({node, className, children, ...props}) { 
                                        const match = /language-(\w+)/.exec(className || ''); 
                                        const isInline = !match && !String(children).includes('\n'); 

                                        if (isInline) {
                                          return <code className={className} {...props}>{children}</code>;
                                        }
                                        return (
                                          <CodeBlock 
                                            language={match ? match[1] : 'text'} 
                                            value={String(children).replace(/\n$/, '')} 
                                            theme={theme}
                                            onShowToast={onShowToast}
                                            lang={language}
                                          />
                                        );
                                    },
                                    a({href, children}) {
                                        return (
                                            <a href={href} target="_blank" rel="noopener noreferrer">
                                                {children}
                                                <ExternalLink className="w-3 h-3 inline-block ml-0.5 opacity-70" />
                                            </a>
                                        );
                                    },
                                    img({src, alt}) {
                                        return <img src={src} alt={alt} onClick={() => { if (typeof src === 'string') handleImageClick(src); }} style={{cursor: 'pointer'}} />;
                                    },
                                    input({checked, readOnly}) {
                                        return <input type="checkbox" checked={checked} readOnly={readOnly} className="mr-2 accent-primary-600 rounded w-4 h-4 align-text-bottom cursor-default" />;
                                    }
                                }}
                            >
                                {content}
                            </ReactMarkdown>
                        )}
                    </div>
                    )}
                </>
                )}
            </div>

            <div className="flex flex-wrap items-center gap-x-2 gap-y-1 mt-1 px-1 min-h-[1.5rem]">
                <span className="text-[10px] text-gray-400 dark:text-gray-500 whitespace-nowrap">{new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                {msg.role === Role.MODEL && !msg.isError && (
                <div className="flex flex-wrap items-center gap-1">
                    {msg.keyIndex && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title="API Key Index">#{msg.keyIndex}</span>
                    )}
                    {showModelName && msg.model && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 break-all max-w-[250px]" title="Model Used">{msg.model}</span>
                    )}
                    {showResponseTimer && msg.executionTime && (
                        <div className="flex items-center gap-0.5 text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title="Response Time">
                            <Clock className="w-2.5 h-2.5" />
                            <span>{t('label.response_time', language).replace('{duration}', (msg.executionTime / 1000).toFixed(1))}</span>
                        </div>
                    )}
                </div>
                )}
                {!isLoading && !isEditing && (
                <div className={`flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity`}>
                    <button 
                    onClick={() => startEditing(msg)} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={t('action.edit', language)}
                    aria-label={t('action.edit_message', language)}
                    >
                    <Edit2 className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleRegenerateClick} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={msg.role === Role.USER ? t('action.regenerate_from_user_message', language) : t('action.regenerate_response', language)}
                    aria-label={t('action.regenerate', language)}
                    >
                    <RefreshCw className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleDeleteClick} 
                    className={`p-4 md:p-1 transition-colors ${isConfirmingDelete ? 'text-red-500 bg-red-50 dark:bg-red-900/20 rounded' : 'text-gray-400 hover:text-red-500'}`}
                    title={isConfirmingDelete ? t('action.confirm_delete', language) : t('action.delete', language)}
                    aria-label={t('action.delete_message', language)}
                    >
                    <Trash2 className="w-3.5 h-3.5" />
                    </button>
                </div>
                )}
            </div>
            </div>
        </div>
    </div>
  );
}, (prev, next) => {
  return (
    prev.msg === next.msg &&
    prev.isEditing === next.isEditing &&
    prev.isConfirmingDelete === next.isConfirmingDelete &&
    prev.isLoading === next.isLoading &&
    prev.bubbleTransparency === next.bubbleTransparency &&
    prev.textWrapping === next.textWrapping &&
    prev.fontSize === next.fontSize &&
    prev.showModelName === next.showModelName &&
    prev.showResponseTimer === next.showResponseTimer &&
    prev.language === next.language &&
    prev.theme === next.theme &&
    prev.kirbyThemeColor === next.kirbyThemeColor &&
    prev.smoothAnimation === next.smoothAnimation &&
    prev.isLast === next.isLast &&
    prev.avatarVisibility === next.avatarVisibility
  );
});

"use client";

import React, { useEffect, useRef, useState } from 'react';
import { Send, Square, Zap, Paperclip, X, Plus, Image as ImageIcon, FileText } from 'lucide-react';
import { Language, Message, Theme } from '../types';
import { t } from '../utils/i18n';

interface ChatInputProps {
  input: string;
  setInput: (value: string) => void;
  inputImages?: string[]; // New: base64 images
  setInputImages?: (images: string[]) => void;
  onSend: () => void;
  onStop: () => void;
  isLoading: boolean;
  isDisabled: boolean;
  fontSize: number;
  language: Language;
  activeKeysCount: number;
  showTokenUsage?: boolean;
  history?: Message[];
  historyLimit?: number;
  onGetTokenCount?: (text: string) => Promise<number>;
  theme?: Theme;
}

const ChatInput: React.FC<ChatInputProps> = ({
  input,
  setInput,
  inputImages = [],
  setInputImages,
  onSend,
  onStop,
  isLoading,
  isDisabled,
  fontSize,
  language,
  activeKeysCount,
  showTokenUsage = false,
  history = [],
  historyLimit = 0,
  onGetTokenCount,
  theme
}) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textFileInputRef = useRef<HTMLInputElement>(null);
  const [tokenEstimate, setTokenEstimate] = useState(0);
  const [exactTokenCount, setExactTokenCount] = useState<number | null>(null);
  const [isToolsOpen, setIsToolsOpen] = useState(false);

  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl';

  // Determine dynamic min-height based on fontSize to prevent scrollbars for single lines
  const minHeight = Math.floor(fontSize * 1.5 + 36);
  const maxHeight = showTokenUsage ? 224 : 192;

  // Debounced API call for exact token count
  useEffect(() => {
    if (!showTokenUsage || !onGetTokenCount) return;
    setExactTokenCount(null);
    const timer = setTimeout(async () => {
        if (input.trim() || history.length > 0) {
            try {
                const count = await onGetTokenCount(input);
                if (count > -1) {
                    setExactTokenCount(count);
                }
            } catch (e) { }
        }
    }, 1000);
    return () => clearTimeout(timer);
  }, [input, history, showTokenUsage, onGetTokenCount]);

  // Estimate tokens (local fallback)
  useEffect(() => {
    if (!showTokenUsage) return;
    let textToCount = input;
    let historyContext = history;
    if (historyLimit > 0 && history.length > historyLimit) {
        historyContext = history.slice(-historyLimit);
    }
    const historyText = historyContext.map(m => m.text).join('');
    const totalChars = textToCount.length + historyText.length;
    const estimate = Math.ceil(totalChars / 4);
    setTokenEstimate(estimate);
  }, [input, history, showTokenUsage, historyLimit]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.nativeEvent.isComposing) return;
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      onSend();
    }
  };

  const handleInput = (e: React.FormEvent<HTMLTextAreaElement>) => {
    const target = e.target as HTMLTextAreaElement;
    target.style.height = 'auto';
    target.style.height = `${Math.min(target.scrollHeight, maxHeight)}px`;
  };

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      const currentScrollHeight = textareaRef.current.scrollHeight;
      const targetHeight = Math.min(Math.max(currentScrollHeight, minHeight), maxHeight);
      textareaRef.current.style.height = `${targetHeight}px`;
    }
  }, [input, minHeight, maxHeight, fontSize]);

  const displayCount = exactTokenCount !== null ? exactTokenCount : tokenEstimate;

  // --- Image Handling ---

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0 && setInputImages) {
      const files = Array.from(e.target.files) as File[];
      readAndAddImages(files);
      setIsToolsOpen(false); // Close menu after selection
    }
    if (fileInputRef.current) fileInputRef.current.value = ''; // Reset input
  };

  const handleTextFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = (ev) => {
        const content = ev.target?.result as string;
        const textToAppend = `\n\n\`\`\`${file.name}\n${content}\n\`\`\`\n`;
        // Use input prop directly since setInput type definition in props doesn't support functional update
        setInput((input + textToAppend).trimStart());
        setIsToolsOpen(false);
      };
      reader.readAsText(file);
    }
    if (textFileInputRef.current) textFileInputRef.current.value = '';
  };

  const handlePaste = (e: React.ClipboardEvent) => {
    if (!setInputImages) return;
    const items = e.clipboardData.items;
    const files: File[] = [];
    for (let i = 0; i < items.length; i++) {
        if (items[i].type.indexOf('image') !== -1) {
            const file = items[i].getAsFile();
            if (file) files.push(file);
        }
    }
    if (files.length > 0) {
        readAndAddImages(files);
    }
  };

  const readAndAddImages = (files: File[]) => {
      if (!setInputImages) return;
      const newImages: string[] = [];
      let processed = 0;

      files.forEach(file => {
          const reader = new FileReader();
          reader.onload = (e) => {
              if (e.target?.result && typeof e.target.result === 'string') {
                  newImages.push(e.target.result);
              }
              processed++;
              if (processed === files.length) {
                  setInputImages([...inputImages, ...newImages]);
              }
          };
          reader.readAsDataURL(file);
      });
  };

  const removeImage = (index: number) => {
      if (!setInputImages) return;
      const updated = [...inputImages];
      updated.splice(index, 1);
      setInputImages(updated);
  };

  return (
    <div className="p-3 md:p-4 pb-2 bg-transparent flex flex-col items-center">
      <div className={`${containerClass} w-full`}>

        {/* Collapsible Toolbar (Top Left) */}
        <div className="flex items-center gap-2 mb-2 px-1 h-8">
            <button
                onClick={() => setIsToolsOpen(!isToolsOpen)}
                className={`p-1.5 rounded-full transition-all duration-300 ${isToolsOpen ? 'bg-gray-200 dark:bg-gray-700 rotate-45' : 'bg-gray-100 dark:bg-gray-800 hover:bg-gray-200 dark:hover:bg-gray-700'} text-gray-500 dark:text-gray-400`}
                title="Expand tools"
            >
                <Plus className="w-5 h-5" />
            </button>

            <div className={`flex items-center gap-2 overflow-hidden transition-all duration-300 ease-in-out ${isToolsOpen ? 'w-auto opacity-100 translate-x-0' : 'w-0 opacity-0 -translate-x-4 pointer-events-none'}`}>
                 <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 hover:bg-primary-100 dark:hover:bg-primary-900/40 transition-colors text-xs font-medium whitespace-nowrap"
                    title={t('action.upload_image', language)}
                    disabled={isDisabled}
                 >
                    <ImageIcon className="w-4 h-4" />
                    <span>{t('action.upload_image', language)}</span>
                 </button>

                 <button 
                    onClick={() => textFileInputRef.current?.click()}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors text-xs font-medium whitespace-nowrap"
                    title={t('action.upload_file', language)}
                    disabled={isDisabled}
                 >
                    <FileText className="w-4 h-4" />
                    <span>{t('action.upload_file', language)}</span>
                 </button>
            </div>

            <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileSelect} 
                accept="image/*" 
                multiple 
                className="hidden" 
            />
            <input 
                type="file" 
                ref={textFileInputRef} 
                onChange={handleTextFileSelect} 
                accept=".txt,.md,.js,.ts,.py,.json,.html,.css,.csv,.xml" 
                className="hidden" 
            />
        </div>

        {/* Image Preview Area */}
        {inputImages.length > 0 && (
            <div className="flex gap-2 mb-2 overflow-x-auto p-1 scrollbar-hide">
                {inputImages.map((img, idx) => (
                    <div key={idx} className="relative group shrink-0">
                        <img 
                            src={img} 
                            alt={`upload-${idx}`} 
                            className="h-16 w-16 object-cover rounded-lg border border-gray-200 dark:border-gray-700" 
                        />
                        <button 
                            onClick={() => removeImage(idx)}
                            className="absolute -top-1.5 -right-1.5 bg-gray-500 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-500"
                        >
                            <X className="w-3 h-3" />
                        </button>
                    </div>
                ))}
            </div>
        )}

        <div className="relative flex items-center glass-panel rounded-2xl shadow-xl focus-within:ring-2 focus-within:ring-primary-500/50 focus-within:border-primary-500 transition-all">

          <textarea 
            ref={textareaRef}
            value={input} 
            onChange={(e) => setInput(e.target.value)} 
            onKeyDown={handleKeyDown}
            onInput={handleInput}
            onPaste={handlePaste}
            placeholder={activeKeysCount === 0 ? t('input.no_keys', language) : t('input.placeholder', language)} 
            disabled={isDisabled} 
            className={`w-full bg-transparent text-gray-900 dark:text-white p-3 md:p-4 pr-12 resize-none outline-none scrollbar-hide ${showTokenUsage ? 'pb-8 max-h-56' : 'max-h-48'}`}
            rows={1} 
            style={{ height: 'auto', minHeight: `${minHeight}px`, fontSize: `${fontSize}px`, lineHeight: '1.5' }} 
          />

          <div className="absolute right-2 bottom-2 flex flex-col items-end gap-1">
             <button 
              onClick={isLoading ? onStop : onSend} 
              disabled={(!input.trim() && inputImages.length === 0 && !isLoading) || isDisabled} 
              className={`p-2 rounded-xl flex items-center justify-center transition-all border-none ${isLoading ? 'bg-red-500 text-white hover:bg-red-600 shadow-md' : ((input.trim() || inputImages.length > 0) && !isDisabled ? 'bg-primary-600 text-white shadow-lg hover:bg-primary-500' : 'bg-gray-200 text-gray-400 dark:bg-gray-700 dark:text-gray-500 cursor-not-allowed')}`} 
              title={isLoading ? t('action.stop', language) : t('action.send', language)}
            >
              {isLoading ? <Square className="w-5 h-5 fill-current" /> : <Send className="w-5 h-5" />}
            </button>
          </div>

          {showTokenUsage && (
             <div className="absolute left-4 bottom-2 pointer-events-none select-none">
                <span 
                    className={`text-[11px] font-mono flex items-center gap-1 transition-colors ${exactTokenCount !== null ? 'text-primary-600 dark:text-primary-400 font-medium' : 'text-gray-400 dark:text-gray-500'}`}
                    title={exactTokenCount !== null ? t('label.exact_count', language) : t('label.estimated_count', language)}
                >
                   <Zap className="w-3 h-3" />
                   {exactTokenCount === null ? `~${displayCount.toLocaleString()}` : displayCount.toLocaleString()}
                </span>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ChatInput;

